text:
I have tried this with no success on 2.3.1. Looks like this polkit policies are ignored because this should grant access to anyone. Maybe this "get_kinfo_proc() failed for pid XYZ: No such process" is the problem?

1. /usr/local/etc/polkit-1/rules.d/99-pcscd.rules:

  polkit.addRule(function(action, subject) {
    if (action.id == "org.debian.pcsc-lite.access_card") {
      return polkit.Result.YES;
    }
  });

  polkit.addRule(function(action, subject) {
    if (action.id == "org.debian.pcsc-lite.access_pcsc") {
      return polkit.Result.YES;
    }
  });

  polkit.addAdminRule(function(action, subject) {
    if (action.id == "org.debian.pcsc-lite.access_pcsc") {
      return polkit.Result.YES;
    }
  });


2. /usr/local/share/polkit-1/actions/org.debian.pcsc-lite.policy:

<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE policyconfig PUBLIC
 "-//freedesktop//DTD PolicyKit Policy Configuration 1.0//EN"
 "http://www.freedesktop.org/standards/PolicyKit/1.0/policyconfig.dtd">
<policyconfig>
  <vendor>The PCSC-lite Project</vendor>
  <vendor_url>https://pcsclite.apdu.fr/</vendor_url>
<!--  <icon_name>smart-card</icon_name> -->

  <action id="org.debian.pcsc-lite.access_pcsc">
    <description>Access to the PC/SC daemon</description>
    <message>Authentication is required to access the PC/SC daemon</message>
    <defaults>
      <allow_any>yes</allow_any>
      <allow_inactive>yes</allow_inactive>
      <allow_active>yes</allow_active>
    </defaults>
  </action>

  <action id="org.debian.pcsc-lite.access_card">
    <description>Access to the smart card</description>
    <message>Authentication is required to access the smart card</message>
    <defaults>
      <allow_any>yes</allow_any>
      <allow_inactive>yes</allow_inactive>
      <allow_active>yes</allow_active>
    </defaults>
  </action>

</policyconfig>
